using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Options;

public class JwtAuthenticationMiddleware
{
    private readonly RequestDelegate _next;
    private readonly JwtOptions _jwtOptions;

    public JwtAuthenticationMiddleware(RequestDelegate next, IOptions<JwtOptions> jwtOptions)
    {
        _next = next;
        _jwtOptions = jwtOptions.Value;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        var token = context.Request.Headers["Authorization"].FirstOrDefault()?.Split(" ").LastOrDefault();

        if (!string.IsNullOrEmpty(token))
        {
            var jwtToken = new JwtSecurityTokenHandler().ValidateToken(token, _jwtOptions.ValidationParameters, out SecurityToken validatedToken);

            var claims = jwtToken.Claims.Select(claim => new Claim(claim.Type, claim.Value));

            context.User = new ClaimsPrincipal(new ClaimsIdentity(claims));
        }

        await _next(context);
    }
}